sql:
SELECT AVG(temp_in) AS average_temperature
FROM marine_environmental_data
WHERE site_id = 1;

SELECT temp_in
FROM marine_environmental_data
WHERE temp_in > 20;

SELECT COUNT(data_id) AS data_count
FROM marine_environmental_data
WHERE season_id = (SELECT season_id FROM seasons WHERE season_name = 'SUMMER');

SELECT zone_name
FROM zones
ORDER BY zone_name ASC;

external_knowledge:
- 'specific_user' is a username in the users table that can be used to filter data by a particular user; 
- Average inlet temperature is a measure used to compare and rank sites; 
- The top 5 sites are determined based on the ranking of their average inlet temperatures.

sql:
SELECT zone_id, COUNT(waypoint_id) AS waypoint_count
FROM waypoints
GROUP BY zone_id;

SELECT collection_date
FROM marine_environmental_data
ORDER BY collection_date ASC;

SELECT AVG(temp_in) AS average_temperature
FROM marine_environmental_data
